30		void help() override
31		{
32			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
33			log("\n");
34			log("    proc [options] [selection]\n");
35			log("\n");
36			log("This pass calls all the other proc_* passes in the most common order.\n");
37			log("\n");
38			log("    proc_clean\n");
39			log("    proc_rmdead\n");
40			log("    proc_prune\n");
41			log("    proc_init\n");
42			log("    proc_arst\n");
43			log("    proc_rom\n");
44			log("    proc_mux\n");
45			log("    proc_dlatch\n");
46			log("    proc_dff\n");
47			log("    proc_memwr\n");
48			log("    proc_clean\n");
49			log("    opt_expr -keepdc\n");
50			log("\n");
51			log("This replaces the processes in the design with multiplexers,\n");
52			log("flip-flops and latches.\n");
53			log("\n");
54			log("The following options are supported:\n");
55			log("\n");
56			log("    -nomux\n");
57			log("        Will omit the proc_mux pass.\n");
58			log("\n");
59			log("    -norom\n");
60			log("        Will omit the proc_rom pass.\n");
61			log("\n");
62			log("    -global_arst [!]<netname>\n");
63			log("        This option is passed through to proc_arst.\n");
64			log("\n");
65			log("    -ifx\n");
66			log("        This option is passed through to proc_mux. proc_rmdead is not\n");
67			log("        executed in -ifx mode.\n");
68			log("\n");
69			log("    -noopt\n");
70			log("        Will omit the opt_expr pass.\n");
71			log("\n");
72			log("    -latches <auto|warn|error>\n");
