77		{
78			std::string global_arst;
79			std::string latches;
80			bool ifxmode = false;
81			bool nomux = false;
82			bool noopt = false;
83			bool norom = false;
84	
85			log_header(design, "Executing PROC pass (convert processes to netlists).\n");
86			log_push();
87	
88			size_t argidx;
89			for (argidx = 1; argidx < args.size(); argidx++)
90			{
91				if (args[argidx] == "-nomux") {
92					nomux = true;
93					continue;
94				}
95				if (args[argidx] == "-global_arst" && argidx+1 < args.size()) {
96					global_arst = args[++argidx];
97					continue;
98				}
99				if (args[argidx] == "-ifx") {
100					ifxmode = true;
101					continue;
102				}
103				if (args[argidx] == "-noopt") {
104					noopt = true;
105					continue;
106				}
107				if (args[argidx] == "-norom") {
108					norom = true;
109					continue;
110				}
111				if (args[argidx] == "-latches" && argidx+1 < args.size()) {
112					latches = args[++argidx];
113					continue;
114				}
115				break;
116			}
117			extra_args(args, argidx, design);
118	
119			Pass::call(design, "proc_clean");
120			if (!ifxmode)
121				Pass::call(design, "proc_rmdead");
122			Pass::call(design, "proc_prune");
123			Pass::call(design, "proc_init");
124			if (global_arst.empty())
125				Pass::call(design, "proc_arst");
126			else
127				Pass::call(design, "proc_arst -global_arst " + global_arst);
128			if (!norom)
129				Pass::call(design, "proc_rom");
130			if (!nomux)
