132			if (latches.empty())
133				Pass::call(design, "proc_dlatch");
134			else
135				Pass::call(design, "proc_dlatch -latches " + latches);
136			Pass::call(design, "proc_dff");
137			Pass::call(design, "proc_memwr");
138			Pass::call(design, "proc_clean");
139			if (!noopt)
140				Pass::call(design, "opt_expr -keepdc");
