31	RTLIL::SigSpec find_any_lvalue(const RTLIL::Process *proc)
32	{
33		RTLIL::SigSpec lvalue;
34	
35		for (auto sync : proc->syncs)
36		for (auto &action : sync->actions)
37			if (action.first.size() > 0) {
38				lvalue = action.first;
39				lvalue.sort_and_unify();
40				break;
41			}
42	
43		for (auto sync : proc->syncs) {
44			RTLIL::SigSpec this_lvalue;
45			for (auto &action : sync->actions)
46				this_lvalue.append(action.first);
47			this_lvalue.sort_and_unify();
48			RTLIL::SigSpec common_sig = this_lvalue.extract(lvalue);
49			if (common_sig.size() > 0)
50				lvalue = common_sig;
51		}
52	
53		return lvalue;
54	}
55	
56	void gen_dffsr_complex(RTLIL::Module *mod, RTLIL::SigSpec sig_d, RTLIL::SigSpec sig_q, RTLIL::SigSpec clk, bool clk_polarity,
57			std::vector<std::pair<RTLIL::SigSpec, RTLIL::SyncRule*>> &async_rules, RTLIL::Process *proc)
58	{
59		// A signal should be set/cleared if there is a load trigger that is enabled
60		// such that the load value is 1/0 and it is the highest priority trigger
61		RTLIL::SigSpec sig_sr_set = RTLIL::SigSpec(0, sig_d.size());
62		RTLIL::SigSpec sig_sr_clr = RTLIL::SigSpec(0, sig_d.size());
63	
64		// Reverse iterate through the rules as the first ones are the highest priority
65		// so need to be at the top of the mux trees
66		for (auto it = async_rules.crbegin(); it != async_rules.crend(); it++)
67		{
68			const auto& [sync_value, rule] = *it;
69			const auto pos_trig = rule->type == RTLIL::SyncType::ST1 ? rule->signal : mod->Not(NEW_ID, rule->signal);
70	
71			// If pos_trig is true, we have priority at this point in the tree so
72			// set a bit if sync_value has a set bit. Otherwise, defer to the rest
73			// of the priority tree
74			sig_sr_set = mod->Mux(NEW_ID, sig_sr_set, sync_value, pos_trig);
75	
76			// Same deal with clear bit
77			const auto sync_value_inv = mod->Not(NEW_ID, sync_value);
78			sig_sr_clr = mod->Mux(NEW_ID, sig_sr_clr, sync_value_inv, pos_trig);
79		}
80	
81		std::stringstream sstr;
82		sstr << "$procdff$" << (autoidx++);
83	
84		RTLIL::Cell *cell = mod->addDffsr(sstr.str(), clk, sig_sr_set, sig_sr_clr, sig_d, sig_q, clk_polarity);
85		cell->attributes = proc->attributes;
86	
87		log("  created %s cell `%s' with %s edge clock and multiple level-sensitive resets.\n",
88				cell->type.c_str(), cell->name.c_str(), clk_polarity ? "positive" : "negative");
89	}
90	
91	void gen_aldff(RTLIL::Module *mod, RTLIL::SigSpec sig_in, RTLIL::SigSpec sig_set, RTLIL::SigSpec sig_out,
92			bool clk_polarity, bool set_polarity, RTLIL::SigSpec clk, RTLIL::SigSpec set, RTLIL::Process *proc)
93	{
94		std::stringstream sstr;
95		sstr << "$procdff$" << (autoidx++);
96	
97		RTLIL::Cell *cell = mod->addCell(sstr.str(), ID($aldff));
98		cell->attributes = proc->attributes;
99	
100		cell->parameters[ID::WIDTH] = RTLIL::Const(sig_in.size());
101		cell->parameters[ID::ALOAD_POLARITY] = RTLIL::Const(set_polarity, 1);
102		cell->parameters[ID::CLK_POLARITY] = RTLIL::Const(clk_polarity, 1);
103		cell->setPort(ID::D, sig_in);
104		cell->setPort(ID::Q, sig_out);
105		cell->setPort(ID::AD, sig_set);
106		cell->setPort(ID::CLK, clk);
107		cell->setPort(ID::ALOAD, set);
108	
109		log("  created %s cell `%s' with %s edge clock and %s level non-const reset.\n", cell->type, cell->name,
110				clk_polarity ? "positive" : "negative", set_polarity ? "positive" : "negative");
111	}
112	
113	void gen_dff(RTLIL::Module *mod, RTLIL::SigSpec sig_in, RTLIL::Const val_rst, RTLIL::SigSpec sig_out,
114			bool clk_polarity, bool arst_polarity, RTLIL::SigSpec clk, RTLIL::SigSpec *arst, RTLIL::Process *proc)
115	{
116		std::stringstream sstr;
117		sstr << "$procdff$" << (autoidx++);
118	
119		RTLIL::Cell *cell = mod->addCell(sstr.str(), clk.empty() ? ID($ff) : arst ? ID($adff) : ID($dff));
120		cell->attributes = proc->attributes;
121	
122		cell->parameters[ID::WIDTH] = RTLIL::Const(sig_in.size());
123		if (arst) {
124			cell->parameters[ID::ARST_POLARITY] = RTLIL::Const(arst_polarity, 1);
125			cell->parameters[ID::ARST_VALUE] = val_rst;
126		}
127		if (!clk.empty()) {
128			cell->parameters[ID::CLK_POLARITY] = RTLIL::Const(clk_polarity, 1);
129		}
130	
131		cell->setPort(ID::D, sig_in);
132		cell->setPort(ID::Q, sig_out);
133		if (arst)
134			cell->setPort(ID::ARST, *arst);
135		if (!clk.empty())
136			cell->setPort(ID::CLK, clk);
137	
138		if (!clk.empty())
139			log("  created %s cell `%s' with %s edge clock", cell->type, cell->name, clk_polarity ? "positive" : "negative");
140		else
141			log("  created %s cell `%s' with global clock", cell->type, cell->name);
142		if (arst)
143			log(" and %s level reset", arst_polarity ? "positive" : "negative");
144		log(".\n");
145	}
146	
147	void proc_dff(RTLIL::Module *mod, RTLIL::Process *proc, ConstEval &ce)
148	{
149		while (1)
150		{
151			RTLIL::SigSpec sig = find_any_lvalue(proc);
152	
153			if (sig.size() == 0)
154				break;
155	
156			log("Creating register for signal `%s.%s' using process `%s.%s'.\n",
157					mod->name.c_str(), log_signal(sig), mod->name.c_str(), proc->name.c_str());
158	
159			RTLIL::SigSpec insig = RTLIL::SigSpec(RTLIL::State::Sz, sig.size());
160			RTLIL::SyncRule *sync_edge = NULL;
161			RTLIL::SyncRule *sync_always = NULL;
162			bool global_clock = false;
163	
164			// A priority ordered set of rules, pairing the value to be assigned for
165			// that rule to the rule
166			std::vector<std::pair<RTLIL::SigSpec, RTLIL::SyncRule*>> async_rules;
167	
168			// Needed when the async rules are collapsed into one as async_rules
169			// works with pointers to SyncRule
170			RTLIL::SyncRule single_async_rule;
171	
172			for (auto sync : proc->syncs)
173			for (auto &action : sync->actions)
174			{
175				if (action.first.extract(sig).size() == 0)
176					continue;
177	
178				if (sync->type == RTLIL::SyncType::ST0 || sync->type == RTLIL::SyncType::ST1) {
179					RTLIL::SigSpec rstval = RTLIL::SigSpec(RTLIL::State::Sz, sig.size());
180					sig.replace(action.first, action.second, &rstval);
181					async_rules.emplace_back(rstval, sync);
182				}
183				else if (sync->type == RTLIL::SyncType::STp || sync->type == RTLIL::SyncType::STn) {
184					if (sync_edge != NULL && sync_edge != sync)
185						log_error("Multiple edge sensitive events found for this signal!\n");
186					sig.replace(action.first, action.second, &insig);
187					sync_edge = sync;
188				}
189				else if (sync->type == RTLIL::SyncType::STa) {
190					if (sync_always != NULL && sync_always != sync)
191						log_error("Multiple always events found for this signal!\n");
192					sig.replace(action.first, action.second, &insig);
193					sync_always = sync;
194				}
195				else if (sync->type == RTLIL::SyncType::STg) {
196					sig.replace(action.first, action.second, &insig);
197					global_clock = true;
198				}
199				else {
200					log_error("Event with any-edge sensitivity found for this signal!\n");
201				}
202	
203				action.first.remove2(sig, &action.second);
204			}
205	
206			// If all async rules assign the same value, priority ordering between
207			// them doesn't matter so they can be collapsed together into one rule
208			// with the disjunction of triggers
209			if (!async_rules.empty() &&
210			    std::all_of(async_rules.begin(), async_rules.end(), [&](auto& p) {
211			        return p.first == async_rules.front().first;
212			    }))
213			{
214				const auto rstval = async_rules.front().first;
215	
216				// The trigger is the disjunction of existing triggers
217				// (with appropriate negation)
218				RTLIL::SigSpec triggers;
219				for (const auto &[_, it] : async_rules)
220					triggers.append(it->type == RTLIL::SyncType::ST1 ? it->signal : mod->Not(NEW_ID, it->signal));
221	
222				// Put this into the dummy sync rule so it can be treated the same
223				// as ones coming from the module
224				single_async_rule.type = RTLIL::SyncType::ST1;
225				single_async_rule.signal = mod->ReduceOr(NEW_ID, triggers);
226				single_async_rule.actions.push_back(RTLIL::SigSig(sig, rstval));
227	
228				// Replace existing rules with this new rule
229				async_rules.clear();
230				async_rules.emplace_back(rstval, &single_async_rule);
231			}
232	
233			SigSpec sig_q = sig;
234			ce.assign_map.apply(insig);
235			ce.assign_map.apply(sig);
236	
237			// If the reset value assigns the reg to itself, add this as part of
238			// the input signal and delete the rule
239			if (async_rules.size() == 1 && async_rules.front().first == sig) {
240				const auto& [_, rule] = async_rules.front();
241				if (rule->type == RTLIL::SyncType::ST1)
242					insig = mod->Mux(NEW_ID, insig, sig, rule->signal);
243				else
244					insig = mod->Mux(NEW_ID, sig, insig, rule->signal);
245	
246				async_rules.clear();
247			}
248	
249			if (sync_always) {
250				if (sync_edge || !async_rules.empty())
251					log_error("Mixed always event with edge and/or level sensitive events!\n");
252				log("  created direct connection (no actual register cell created).\n");
253				mod->connect(RTLIL::SigSig(sig, insig));
254				continue;
255			}
256	
257			if (!sync_edge && !global_clock)
258				log_error("Missing edge-sensitive event for this signal!\n");
259	
260			// More than one reset value so we derive a dffsr formulation
261			if (async_rules.size() > 1)
262			{
263				log_warning("Complex async reset for dff `%s'.\n", log_signal(sig));
264				gen_dffsr_complex(mod, insig, sig, sync_edge->signal, sync_edge->type == RTLIL::SyncType::STp, async_rules, proc);
265				continue;
266			}
267	
268			// If there is a reset condition in the async rules, use it
269			SigSpec rstval = async_rules.empty() ? RTLIL::SigSpec(RTLIL::State::Sz, sig.size()) : async_rules.front().first;
270			RTLIL::SyncRule* sync_level = async_rules.empty() ? nullptr : async_rules.front().second;
271			ce.assign_map.apply(rstval);
272	
273			if (!rstval.is_fully_const() && !ce.eval(rstval))
274			{
275				log_warning("Async reset value `%s' is not constant!\n", log_signal(rstval));
276				gen_aldff(mod, insig, rstval, sig_q,
277						sync_edge->type == RTLIL::SyncType::STp,
278						sync_level && sync_level->type == RTLIL::SyncType::ST1,
279						sync_edge->signal, sync_level->signal, proc);
280				continue;
281			}
282	
283			gen_dff(mod, insig, rstval.as_const(), sig_q,
284					sync_edge && sync_edge->type == RTLIL::SyncType::STp,
285					sync_level && sync_level->type == RTLIL::SyncType::ST1,
286					sync_edge ? sync_edge->signal : SigSpec(),
287					sync_level ? &sync_level->signal : NULL, proc);
288		}
289	}
290	
291	struct ProcDffPass : public Pass {
292		ProcDffPass() : Pass("proc_dff", "extract flip-flops from processes") { }
293		void help() override
294		{
295			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
296			log("\n");
297			log("    proc_dff [selection]\n");
298			log("\n");
299			log("This pass identifies flip-flops in the processes and converts them to\n");
300			log("d-type flip-flop cells.\n");
301			log("\n");
302		}
303		void execute(std::vector<std::string> args, RTLIL::Design *design) override
304		{
305			log_header(design, "Executing PROC_DFF pass (convert process syncs to FFs).\n");
306	
307			extra_args(args, 1, design);
308	
309			for (auto mod : design->all_selected_modules()) {
310				ConstEval ce(mod);
311				for (auto proc : mod->selected_processes())
312					proc_dff(mod, proc, ce);
313			}
314		}
315	} ProcDffPass;
316	
317	PRIVATE_NAMESPACE_END
