30	PRIVATE_NAMESPACE_BEGIN
31	
32	struct proc_dlatch_db_t
33	{
34		Module *module;
35		SigMap sigmap;
36		FfInitVals initvals;
37	
38		pool<Cell*> generated_dlatches;
39		dict<Cell*, vector<SigBit>> mux_srcbits;
40		dict<SigBit, pair<Cell*, int>> mux_drivers;
41		dict<SigBit, int> sigusers;
42	
43		proc_dlatch_db_t(Module *module) : module(module), sigmap(module)
44		{
45			initvals.set(&sigmap, module);
46	
47			for (auto cell : module->cells())
48			{
49				if (cell->type.in(ID($mux), ID($pmux), ID($bwmux)))
50				{
51					auto sig_y = sigmap(cell->getPort(ID::Y));
52					for (int i = 0; i < GetSize(sig_y); i++)
53						mux_drivers[sig_y[i]] = pair<Cell*, int>(cell, i);
54	
55					pool<SigBit> mux_srcbits_pool;
56					for (auto bit : sigmap(cell->getPort(ID::A)))
57						mux_srcbits_pool.insert(bit);
58					for (auto bit : sigmap(cell->getPort(ID::B)))
59						mux_srcbits_pool.insert(bit);
60	
61					vector<SigBit> mux_srcbits_vec;
62					for (auto bit : mux_srcbits_pool)
63						if (bit.wire != nullptr)
64							mux_srcbits_vec.push_back(bit);
65	
66					mux_srcbits[cell].swap(mux_srcbits_vec);
67				}
68	
69				for (auto &conn : cell->connections())
70					if (!cell->known() || cell->input(conn.first))
71						for (auto bit : sigmap(conn.second))
72							sigusers[bit]++;
73			}
74	
75			for (auto wire : module->wires())
76			{
77				if (wire->port_input)
78					for (auto bit : sigmap(wire))
79						sigusers[bit]++;
80			}
81		}
82	
83		bool quickcheck(const SigSpec &haystack, const SigSpec &needle)
84		{
85			pool<SigBit> haystack_bits = sigmap(haystack).to_sigbit_pool();
86			pool<SigBit> needle_bits = sigmap(needle).to_sigbit_pool();
87	
88			pool<Cell*> cells_queue, cells_visited;
89			pool<SigBit> bits_queue, bits_visited;
90	
91			bits_queue = haystack_bits;
92			while (!bits_queue.empty())
93			{
94				for (auto &bit : bits_queue) {
95					auto it = mux_drivers.find(bit);
96					if (it != mux_drivers.end())
97						if (!cells_visited.count(it->second.first))
98							cells_queue.insert(it->second.first);
99					bits_visited.insert(bit);
100				}
101	
102				bits_queue.clear();
103	
104				for (auto c : cells_queue) {
105					for (auto bit : mux_srcbits[c]) {
106						if (needle_bits.count(bit))
107							return true;
108						if (!bits_visited.count(bit))
109							bits_queue.insert(bit);
110					}
111				}
112	
113				cells_queue.clear();
114			}
115	
116			return false;
117		}
118	
119		struct rule_node_t
120		{
121			// a node is true if "signal" equals "match" and [any
122			// of the child nodes is true or "children" is empty]
123			SigBit signal, match;
124			vector<int> children;
125	
126			bool operator==(const rule_node_t &other) const {
127				return signal == other.signal && match == other.match && children == other.children;
128			}
129	
130			[[nodiscard]] Hasher hash_into(Hasher h) const {
131				h.eat(signal);
132				h.eat(match);
133				h.eat(children);
134				return h;
135			}
136		};
137	
138		enum tf_node_types_t : int {
139			true_node = 1,
140			false_node = 2
141		};
142	
143		idict<rule_node_t, 3> rules_db;
144		dict<int, SigBit> rules_sig;
145	
146		int make_leaf(SigBit signal, SigBit match)
147		{
148			rule_node_t node;
149			node.signal = signal;
150			node.match = match;
151			return rules_db(node);
152		}
153	
154		int make_inner(SigBit signal, SigBit match, int child)
155		{
156			rule_node_t node;
157			node.signal = signal;
158			node.match = match;
159			node.children.push_back(child);
160			return rules_db(node);
161		}
162	
163		int make_inner(const pool<int> &children)
164		{
165			rule_node_t node;
166			node.signal = State::S0;
167			node.match = State::S0;
168			node.children = vector<int>(children.begin(), children.end());
169			std::sort(node.children.begin(), node.children.end());
170			return rules_db(node);
171		}
172	
173		int find_mux_feedback(SigBit haystack, SigBit needle, bool set_undef)
174		{
175			if (sigusers[haystack] > 1)
176				set_undef = false;
177	
178			if (haystack == needle)
179				return true_node;
180	
181			auto it = mux_drivers.find(haystack);
182			if (it == mux_drivers.end())
183				return false_node;
184	
185			Cell *cell = it->second.first;
186			int index = it->second.second;
187	
188			log_assert(cell->type.in(ID($mux), ID($pmux), ID($bwmux)));
189			bool is_bwmux = (cell->type == ID($bwmux));
190			SigSpec sig_a = sigmap(cell->getPort(ID::A));
191			SigSpec sig_b = sigmap(cell->getPort(ID::B));
192			SigSpec sig_s = sigmap(cell->getPort(ID::S));
193			int width = GetSize(sig_a);
194	
195			pool<int> children;
196	
197			int n = find_mux_feedback(sig_a[index], needle, set_undef);
198			if (n != false_node) {
199				if (set_undef && sig_a[index] == needle) {
200					SigSpec sig = cell->getPort(ID::A);
201					sig[index] = State::Sx;
202					cell->setPort(ID::A, sig);
203				}
204				bool sibling_undef = true;
205				for (int i = 0; i < (is_bwmux ? 1 : GetSize(sig_s)); i++)
206					if (sig_b[i*width + index] != State::Sx)
207						sibling_undef = false;
208				if (!sibling_undef) {
209					if (!is_bwmux) {
210						for (int i = 0; i < GetSize(sig_s); i++)
211							n = make_inner(sig_s[i], State::S0, n);
212					} else {
213						n = make_inner(sig_s[index], State::S0, n);
214					}
215				}
216				children.insert(n);
217			}
218	
219			for (int i = 0; i < (is_bwmux ? 1 : GetSize(sig_s)); i++) {
220				n = find_mux_feedback(sig_b[i*width + index], needle, set_undef);
221				if (n != false_node) {
222					if (set_undef && sig_b[i*width + index] == needle) {
223						SigSpec sig = cell->getPort(ID::B);
224						sig[i*width + index] = State::Sx;
225						cell->setPort(ID::B, sig);
226					}
227					bool sibling_undef = (sig_a[index] == State::Sx);
228					if (!is_bwmux)
229						for (int j = 0; j < GetSize(sig_s); j++)
230							if (j != i && sig_b[j*width + index] != State::Sx)
231								sibling_undef = false;
232					if (!sibling_undef)
233						n = make_inner(sig_s[is_bwmux ? index : i], State::S1, n);
234					children.insert(n);
235				}
236			}
237	
238			if (children.empty())
239				return false_node;
240	
241			return make_inner(children);
242		}
243	
244		int find_mux_constant(SigBit haystack, State needle, bool set_undef)
245		{
246			if (sigusers[haystack] > 1)
247				set_undef = false;
248	
249			if (haystack == SigBit(needle))
250				return true_node;
251	
252			auto it = mux_drivers.find(haystack);
253			if (it == mux_drivers.end())
254				return false_node;
255	
256			Cell *cell = it->second.first;
257			int index = it->second.second;
258	
259			log_assert(cell->type.in(ID($mux), ID($pmux), ID($bwmux)));
260			bool is_bwmux = (cell->type == ID($bwmux));
261			SigSpec sig_a = sigmap(cell->getPort(ID::A));
262			SigSpec sig_b = sigmap(cell->getPort(ID::B));
263			SigSpec sig_s = sigmap(cell->getPort(ID::S));
264			int width = GetSize(sig_a);
265	
266			pool<int> children;
267	
268			int n = find_mux_constant(sig_a[index], needle, set_undef);
269			if (n != false_node) {
270				if (set_undef && sig_a[index] == SigBit(needle)) {
271					SigSpec sig = cell->getPort(ID::A);
272					sig[index] = State::Sx;
273					cell->setPort(ID::A, sig);
274				}
275				if (!is_bwmux) {
276					for (int i = 0; i < GetSize(sig_s); i++)
277						n = make_inner(sig_s[i], State::S0, n);
278				} else {
279					n = make_inner(sig_s[index], State::S0, n);
280				}
281				children.insert(n);
282			}
283	
284			for (int i = 0; i < (is_bwmux ? 1 : GetSize(sig_s)); i++) {
285				n = find_mux_constant(sig_b[i*width + index], needle, set_undef);
286				if (n != false_node) {
287					if (set_undef && sig_b[i*width + index] == SigBit(needle)) {
288						SigSpec sig = cell->getPort(ID::B);
289						sig[i*width + index] = State::Sx;
290						cell->setPort(ID::B, sig);
291					}
292					children.insert(make_inner(sig_s[is_bwmux ? index : i], State::S1, n));
293				}
294			}
295	
296			if (children.empty())
297				return false_node;
298	
299			return make_inner(children);
300		}
301	
302		SigBit make_hold(int n, string &src)
303		{
304			if (n == true_node)
305				return State::S1;
306	
307			if (n == false_node)
308				return State::S0;
309	
310			if (rules_sig.count(n))
311				return rules_sig.at(n);
312	
313			const rule_node_t &rule = rules_db[n];
314			SigSpec and_bits;
315	
316			if (rule.signal != rule.match) {
317				if (rule.match == State::S1)
318					and_bits.append(rule.signal);
319				else if (rule.match == State::S0)
320					and_bits.append(module->Not(NEW_ID, rule.signal, false, src));
321				else
322					and_bits.append(module->Eq(NEW_ID, rule.signal, rule.match, false, src));
323			}
324	
325			if (!rule.children.empty()) {
326				SigSpec or_bits;
327				for (int k : rule.children)
328					or_bits.append(make_hold(k, src));
329				and_bits.append(module->ReduceOr(NEW_ID, or_bits, false, src));
330			}
331	
332			if (GetSize(and_bits) == 2)
333				and_bits = module->And(NEW_ID, and_bits[0], and_bits[1], false, src);
334			log_assert(GetSize(and_bits) == 1);
335	
336			rules_sig[n] = and_bits[0];
337			return and_bits[0];
338		}
339	
340		void fixup_mux(Cell *cell)
341		{
342			SigSpec sig_a = cell->getPort(ID::A);
343			SigSpec sig_b = cell->getPort(ID::B);
344			SigSpec sig_s = cell->getPort(ID::S);
345			SigSpec sig_any_valid_b;
346	
347			SigSpec sig_new_b, sig_new_s;
348			for (int i = 0; i < GetSize(sig_s); i++) {
349				SigSpec b = sig_b.extract(i*GetSize(sig_a), GetSize(sig_a));
350				if (!b.is_fully_undef()) {
351					sig_any_valid_b = b;
352					sig_new_b.append(b);
353					sig_new_s.append(sig_s[i]);
354				}
355			}
356	
357			if (sig_new_s.empty()) {
358				sig_new_b = sig_a;
359				sig_new_s = State::S0;
360			}
361	
362			if (sig_a.is_fully_undef() && !sig_any_valid_b.empty())
363				cell->setPort(ID::A, sig_any_valid_b);
364	
365			if (GetSize(sig_new_s) == 1) {
366				cell->type = ID($mux);
367				cell->unsetParam(ID::S_WIDTH);
368			} else {
369				cell->type = ID($pmux);
370				cell->setParam(ID::S_WIDTH, GetSize(sig_new_s));
371			}
372	
373			cell->setPort(ID::B, sig_new_b);
374			cell->setPort(ID::S, sig_new_s);
375		}
376	
377		void fixup_muxes()
378		{
379			pool<Cell*> visited, queue;
380			dict<Cell*, pool<SigBit>> upstream_cell2net;
381			dict<SigBit, pool<Cell*>> upstream_net2cell;
382	
383			CellTypes ct;
384			ct.setup_internals();
385	
386			for (auto cell : module->cells())
387			for (auto conn : cell->connections()) {
388				if (cell->input(conn.first))
389					for (auto bit : sigmap(conn.second))
390						upstream_cell2net[cell].insert(bit);
391				if (cell->output(conn.first))
392					for (auto bit : sigmap(conn.second))
393						upstream_net2cell[bit].insert(cell);
394			}
395	
396			queue = generated_dlatches;
397			while (!queue.empty())
398			{
399				pool<Cell*> next_queue;
400	
401				for (auto cell : queue) {
402					if (cell->type.in(ID($mux), ID($pmux)))
403						fixup_mux(cell);
404					for (auto bit : upstream_cell2net[cell])
405						for (auto cell : upstream_net2cell[bit])
406							next_queue.insert(cell);
407					visited.insert(cell);
408				}
409	
410				queue.clear();
411				for (auto cell : next_queue) {
412					if (!visited.count(cell) && ct.cell_known(cell->type))
413						queue.insert(cell);
414				}
415			}
416		}
417	};
418	
419	enum LatchPolicy {
420		POLICY_INFO,
421		POLICY_WARN,
422		POLICY_ERROR
423	};
424	
425	void proc_dlatch(proc_dlatch_db_t &db, RTLIL::Process *proc, LatchPolicy policy)
426	{
427		RTLIL::SigSig latches_bits, nolatches_bits;
428		dict<SigBit, SigBit> latches_out_in;
429		dict<SigBit, int> latches_hold, latches_rst, latches_set;
430		std::string src = proc->get_src_attribute();
431	
432		for (auto sr : proc->syncs)
433		{
434			if (sr->type != RTLIL::SyncType::STa) {
435				continue;
436			}
437	
438			if (proc->get_bool_attribute(ID::always_ff))
439				log_error("Found non edge/level sensitive event in always_ff process `%s.%s'.\n",
440						db.module->name.c_str(), proc->name.c_str());
441	
442			for (auto ss : sr->actions)
443			{
444				db.sigmap.apply(ss.first);
445				db.sigmap.apply(ss.second);
446	
447				if (!db.quickcheck(ss.second, ss.first)) {
448					nolatches_bits.first.append(ss.first);
449					nolatches_bits.second.append(ss.second);
450					continue;
451				}
452	
453				for (int i = 0; i < GetSize(ss.first); i++)
454					latches_out_in[ss.first[i]] = ss.second[i];
455			}
456			sr->actions.clear();
457		}
458	
459		latches_out_in.sort();
460		for (auto &it : latches_out_in) {
461			if (db.find_mux_feedback(it.second, it.first, false) == db.false_node) {
462				nolatches_bits.first.append(it.first);
463				nolatches_bits.second.append(it.second);
464				continue;
465			}
466	
467			latches_bits.first.append(it.first);
468			latches_bits.second.append(it.second);
469			int nrst = db.find_mux_constant(it.second, State::S0, false);
470			int nset = db.find_mux_constant(it.second, State::S1, false);
471			bool has_rst = (nrst != db.false_node);
472			bool has_set = (nset != db.false_node);
473	
474			if (has_rst && !has_set)
475				nrst = db.find_mux_constant(it.second, State::S0, true);
476			else if (has_set && !has_rst)
477				nset = db.find_mux_constant(it.second, State::S1, true);
478			else
479				nrst = nset = db.false_node;
480	
481			int n = db.find_mux_feedback(it.second, it.first, true);
482			log_assert(n != db.false_node);
483			latches_hold[it.first] = n;
484			latches_rst[it.first] = nrst;
485			latches_set[it.first] = nset;
486		}
487	
488		int offset = 0;
489		for (auto chunk : nolatches_bits.first.chunks()) {
490			SigSpec lhs = chunk, rhs = nolatches_bits.second.extract(offset, chunk.width);
491			bool is_nosync = true;
492			for (auto bit : lhs)
493				if (bit.wire == nullptr || !bit.wire->get_bool_attribute(ID::nosync)) {
494					is_nosync = false;
495					break;
496				}
497	
498			if (proc->get_bool_attribute(ID::always_latch) && !is_nosync)
499				log_error("No latch inferred for signal `%s.%s' from always_latch process `%s.%s'.\n",
500						db.module->name.c_str(), log_signal(lhs), db.module->name.c_str(), proc->name.c_str());
501			else if (!is_nosync)
502				log("No latch inferred for signal `%s.%s' from process `%s.%s'.\n",
503						db.module->name.c_str(), log_signal(lhs), db.module->name.c_str(), proc->name.c_str());
504			for (auto &bit : lhs) {
505				State val = db.initvals(bit);
506				if (db.initvals(bit) != State::Sx) {
507					log("Removing init bit %s for non-memory siginal `%s.%s` in process `%s.%s`.\n", log_signal(val), db.module->name, log_signal(bit), db.module->name, proc->name);
508				}
509				db.initvals.remove_init(bit);
510			}
511			db.module->connect(lhs, rhs);
512			offset += chunk.width;
513		}
514	
515		offset = 0;
516		while (offset < GetSize(latches_bits.first))
517		{
518			int width = 1;
519			SigBit obit = latches_bits.first[offset];
520			int n = latches_hold[obit];
521			int nrst = latches_rst[obit];
522			int nset = latches_set[obit];
523			Wire *w = obit.wire;
524	
525			if (w != nullptr)
526			{
527				while (offset+width < GetSize(latches_bits.first) &&
528						n == latches_hold[latches_bits.first[offset+width]] &&
529						nrst == latches_rst[latches_bits.first[offset+width]] &&
530						nset == latches_set[latches_bits.first[offset+width]] &&
531						w == latches_bits.first[offset+width].wire)
532					width++;
533	
534				SigSpec lhs = latches_bits.first.extract(offset, width);
535				SigSpec rhs = latches_bits.second.extract(offset, width);
536	
537				SigBit en = db.module->Not(NEW_ID, db.make_hold(n, src));
538				bool has_rst = (nrst != db.false_node);
539				bool has_set = (nset != db.false_node);
540	
541				Cell *cell;
542				if (has_rst)
543					cell = db.module->addAdlatch(NEW_ID, en, db.make_hold(nrst, src), rhs, lhs, RTLIL::Const(State::S0, width));
544				else if (has_set)
545					cell = db.module->addAdlatch(NEW_ID, en, db.make_hold(nset, src), rhs, lhs, RTLIL::Const(State::S1, width));
546				else
547					cell = db.module->addDlatch(NEW_ID, en, rhs, lhs);
548				cell->set_src_attribute(src);
549				db.generated_dlatches.insert(cell);
550	
551				if (proc->get_bool_attribute(ID::always_comb))
552					log_error("Latch inferred for signal `%s.%s' from always_comb process `%s.%s'.\n",
553							db.module->name.c_str(), log_signal(lhs), db.module->name.c_str(), proc->name.c_str());
554				else if (policy == POLICY_ERROR)
555					log_error("Latch inferred for signal `%s.%s' from process `%s.%s': %s\n",
556							db.module->name.c_str(), log_signal(lhs), db.module->name.c_str(), proc->name.c_str(), cell);
557				else if (policy == POLICY_WARN)
558					log_warning("Latch inferred for signal `%s.%s' from process `%s.%s': %s\n",
559							db.module->name.c_str(), log_signal(lhs), db.module->name.c_str(), proc->name.c_str(), cell);
560				else
561					log("Latch inferred for signal `%s.%s' from process `%s.%s': %s\n",
562							db.module->name.c_str(), log_signal(lhs), db.module->name.c_str(), proc->name.c_str(), cell);
563			}
564	
565			offset += width;
566		}
567	}
568	
569	struct ProcDlatchPass : public Pass {
570		ProcDlatchPass() : Pass("proc_dlatch", "extract latches from processes") { }
571		void help() override
572		{
573			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
574			log("\n");
575			log("    proc_dlatch [options] [selection]\n");
576			log("\n");
577			log("This pass identifies latches in the processes and converts them to\n");
578			log("d-type latches.\n");
579			log("\n");
580			log("    -latches <info|warn|error>\n");
581			log("        controls how the inference of a latch is reported. Alternatively, one\n");
582			log("        can use the 'proc.latches' scratchpad variable. Defaults to 'warn'.\n");
583			log("\n");
584		}
585		void execute(std::vector<std::string> args, RTLIL::Design *design) override
586		{
587			log_header(design, "Executing PROC_DLATCH pass (convert process syncs to latches).\n");
588	
589			std::string policy_str;
590	
591			size_t argidx;
592			for (argidx = 1; argidx < args.size(); argidx++) {
593				if (args[argidx] == "-latches" && argidx+1 < args.size()) {
594					policy_str = args[++argidx];
595					continue;
596				}
597				break;
598			}
599			extra_args(args, argidx, design);
600	
601			if (policy_str.empty())
602				policy_str = design->scratchpad_get_string("proc.latches", "warn");
603	
604			LatchPolicy policy;
605			if (policy_str == "info")
606				policy = POLICY_INFO;
607			else if (policy_str == "warn")
608				policy = POLICY_WARN;
609			else if (policy_str == "error")
610				policy = POLICY_ERROR;
611			else
612				log_cmd_error("Invalid value '%s' for -latches (expected info|warn|error).\n", policy_str.c_str());
613	
614			for (auto mod : design->all_selected_modules()) {
615				proc_dlatch_db_t db(mod);
616				for (auto proc : mod->selected_processes())
617					proc_dlatch(db, proc, policy);
618				db.fixup_muxes();
619			}
620		}
621	} ProcDlatchPass;
622	
623	PRIVATE_NAMESPACE_END
624

